import { randomUUID } from 'crypto';
import { Autumn } from 'autumn-js';

const autumn = new Autumn(process.env.AUTUMN_SECRET_KEY);

/**
 * Generate AI completion with budget locking using Autumn's balance locking pattern
 * @param {string} customerId - Customer ID
 * @param {number} maxTokens - Maximum tokens to use
 * @returns {Promise<{lockId: string, tokensUsed: number, confirmed: boolean}>}
 */
export async function generateWithBudget(customerId, maxTokens) {
  // Generate a unique lockId
  const lockId = `completion_${randomUUID()}`;

  try {
    // Step 1: Lock - Reserve the balance
    const checkResult = await autumn.customers.check({
      customerId,
      featureId: 'ai-tokens',
      requiredBalance: maxTokens,
      sendEvent: true,
      lock: {
        enabled: true,
        lockId,
        expiresAt: Date.now() + 60000 // 60 seconds from now
      }
    });

    // Step 2: Check if allowed
    if (!checkResult.allowed) {
      throw new Error('Insufficient ai-tokens balance');
    }

    // Step 3: Work - Simulate AI generation
    await new Promise(resolve => setTimeout(resolve, 100)); // 100ms delay
    const tokensUsed = Math.floor(maxTokens * 0.75);

    // Step 4: Finalize - Confirm the actual usage
    await autumn.balances.finalize({
      lockId,
      action: 'confirm',
      overrideValue: tokensUsed
    });

    // Return result
    return {
      lockId,
      tokensUsed,
      confirmed: true
    };
  } catch (error) {
    // Step 5: On error, release the lock
    try {
      await autumn.balances.finalize({
        lockId,
        action: 'release'
      });
    } catch (finalizeError) {
      // Log but don't mask the original error
      console.error('Failed to release lock:', finalizeError);
    }

    // Re-throw the original error
    throw error;
  }
}

