import { generateWithBudget } from './ai_generator.js';
import { writeFileSync } from 'fs';

async function main() {
  try {
    console.log('Starting AI generation with budget locking...');

    // Generate AI completion with budget
    const result = await generateWithBudget('user_test_001', 1000);

    console.log('Generation completed successfully:', result);

    // Write result to JSON file
    writeFileSync(
      './generation_result.json',
      JSON.stringify(result, null, 2),
      'utf-8'
    );

    console.log('Result written to generation_result.json');
  } catch (error) {
    console.error('Generation failed:', error.message);
    process.exit(1);
  }
}

